/**
 * Quantifies the chunk pipeline's batched flat prefix against the chunked-memo cursor and the row-at-a-time chain it
 * replaces, on a CHAIN-prefix shape (the star benchmarks have flatCount=1, so their prefixes never probe). The chain is
 * four patterns deep with the last leg unprojected: the flat prefix is three deep, its depth-1 probe keys arrive
 * grouped (run replay), and its depth-2 keys repeat only non-adjacently (per-key memo). The {@code mode} parameter pins
 * the prefix strategy through system properties — each mode runs in its own JMH fork, the properties are set in
 * {@code @Setup} before the evaluation classes load their static flags, and setup verifies the expected engagement
 * counters so a silently wrong mode fails the run instead of measuring the wrong thing.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class ChunkPipelineChainBenchmark {

	private static final String EX = "http://example.com/";
	private static final String CHUNK_FLAG = "rdf4j.lmdb.chunkPipeline.enabled";
	private static final String MEMO_FLAG = "rdf4j.lmdb.factorizedRows.chunkedPrefix.enabled";

	private static final int HUBS = 100;
	private static final int SUBJECTS_PER_HUB = 20;
	private static final int MIDS_PER_HUB = 50;
	private static final int TARGETS_PER_MID = 2;

	@Param({ "chunkPipeline", "chunkedMemo", "rowChain" })
	public String mode;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expectedRows;

	@Setup(Level.Trial)
	public void setUp() {
		switch (mode) {
		case "chunkPipeline":
			System.setProperty(CHUNK_FLAG, "true");
			break;
		case "chunkedMemo":
			System.setProperty(CHUNK_FLAG, "false");
			System.setProperty(MEMO_FLAG, "true");
			break;
		case "rowChain":
			System.setProperty(CHUNK_FLAG, "false");
			System.setProperty(MEMO_FLAG, "false");
			break;
		default:
			throw new IllegalArgumentException(mode);
		}
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			IRI p4 = vf.createIRI(EX, "p4");
			conn.begin();
			for (int h = 0; h < HUBS; h++) {
				IRI hub = vf.createIRI(EX, "hub" + h);
				for (int s = 0; s < SUBJECTS_PER_HUB; s++) {
					conn.add(vf.createIRI(EX, "s" + h + "_" + s), p1, hub);
				}
				for (int m = 0; m < MIDS_PER_HUB; m++) {
					IRI mid = vf.createIRI(EX, "mid" + h + "_" + m);
					conn.add(hub, p2, mid);
					for (int t = 0; t < TARGETS_PER_MID; t++) {
						IRI target = vf.createIRI(EX, "t" + h + "_" + m + "_" + t);
						conn.add(mid, p3, target);
						conn.add(target, p4, vf.createIRI(EX, "leaf" + h + "_" + m + "_" + t));
					}
				}
			}
			conn.commit();
		}
		query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?w WHERE {\n"
				+ "  ?s ex:p1 ?x .\n"
				+ "  ?x ex:p2 ?y .\n"
				+ "  ?y ex:p3 ?w .\n"
				+ "  ?w ex:p4 ?z .\n"
				+ "}";
		expectedRows = (long) HUBS * SUBJECTS_PER_HUB * MIDS_PER_HUB * TARGETS_PER_MID;
		verifyModeEngagement();
	}

	/** One explain run proving the intended prefix strategy actually runs (the flags freeze at class load). */
	private void verifyModeEngagement() {
		String strategy;
		try (SailRepositoryConnection conn = repository.getConnection()) {
			strategy = findStrategy(conn.prepareTupleQuery(query)
					.explain(Explanation.Level.Telemetry)
					.toGenericPlanNode());
		}
		String expected;
		switch (mode) {
		case "chunkPipeline":
			expected = "chunkPipeline(";
			break;
		case "chunkedMemo":
			expected = "prefix=chunkedMemo";
			break;
		default:
			expected = "prefix=chain";
			break;
		}
		if (strategy == null || !strategy.contains(expected)) {
			throw new IllegalStateException(mode + ": expected strategy containing '" + expected + "' but was '"
					+ strategy + "'");
		}
	}

	private static String findStrategy(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String value = node.getStringMetricActual("nativeExecutionPath");
		if (value != null) {
			return value;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String found = findStrategy(child);
				if (found != null) {
					return found;
				}
			}
		}
		return null;
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
		System.clearProperty(CHUNK_FLAG);
		System.clearProperty(MEMO_FLAG);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			long rows = 0;
			try (TupleQueryResult result = conn.prepareTupleQuery(query).evaluate()) {
				while (result.hasNext()) {
					result.next();
					rows++;
				}
			}
			if (rows != expectedRows) {
				throw new IllegalStateException(mode + ": expected " + expectedRows + " rows but got " + rows);
			}
			return rows;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("ChunkPipelineChainBenchmark")
				.build();
		new Runner(opt).run();
	}
}
